  ('aboriginal-6f0ba476-moex-00538', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '假設一個劣等財的價格上升。下列何者正確？', '["替代效果及所得效果都會使此物品的消費量增加", "替代效果及所得效果都會使此物品的消費量減少", "替代效果會使此物品的消費量增加，但所得效果會使此物品的消費量減少", "替代效果會使此物品的消費量減少，但所得效果會使此物品的消費量增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "7948d6976ec8", "answer_pdf_sha1": "db992a01dd7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
